{"path": "/tmp/sv-560ebf83b8d740cd9948b445347847a7/RecipeShare/Services/RecipeService.cs", "file_text": "using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nFresh mozzarella\nSan Marzano tomatoes\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook pasta in salted water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, add egg mixture and toss quickly.\n6. Serve immediately with extra pecorino.", AverageRating = 4.8, RatingCount = 20 },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nGarlic\nGinger\nOnion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomatoes and simmer 15 minutes.\n5. Stir in cream and spices.\n6. Add chicken, simmer 10 minutes.\n7. Serve with basmati rice or naan.", AverageRating = 4.6, RatingCount = 15 },
            new() { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nChili flakes", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Press and cube tofu, pan-fry until golden.\n3. Mix tamarind paste, fish sauce, sugar for sauce.\n4. Stir-fry noodles with sauce.\n5. Add tofu, bean sprouts, green onions.\n6. Serve with crushed peanuts and lime wedges.", AverageRating = 4.3, RatingCount = 8 },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 10 },
            new() { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla.\n4. Fold chocolate mixture into eggs.\n5. Add flour and fold gently.\n6. Pour into greased ramekins.\n7. Bake 12-14 minutes (center should be soft).\n8. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 25 },
            new() { Id = 7, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoy sauce\nSoft-boiled egg\nChashu pork\nGreen onions\nNori\nCorn\nButter", Steps = "1. Simmer broth with miso paste and soy sauce.\n2. Cook ramen noodles according to package.\n3. Prepare soft-boiled egg (6.5 minutes).\n4. Slice chashu pork.\n5. Assemble bowl: noodles, broth, toppings.\n6. Add butter pat on top and serve hot.", AverageRating = 4.7, RatingCount = 18 },
            new() { Id = 8, Title = "Greek Salad", Category = "Mediterranean", Ingredients = "Cucumber\nTomatoes\nRed onion\nKalamata olives\nFeta cheese\nOlive oil\nRed wine vinegar\nOregano", Steps = "1. Chop cucumber, tomatoes, and red onion.\n2. Combine in a large bowl.\n3. Add olives and crumbled feta.\n4. Whisk olive oil, vinegar, and oregano.\n5. Drizzle dressing over salad.\n6. Toss gently and serve.", AverageRating = 4.1, RatingCount = 6 },
        };
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
        {
            _ratings[recipeId] = new List<int>();
        }

        _ratings[recipeId].Add(stars);
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(
            (recipe.AverageRating * (recipe.RatingCount - 1) + stars) / recipe.RatingCount, 1);
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}
"}

