arguments.new_str:
@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>🍳 RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mt-2">
    @foreach (var category in Categories)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                    <p class="card-text">Explore our @category recipes</p>
                    <a href="/recipes/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Japanese" => "🍜",
        "Mediterranean" => "🥗",
        _ => "🍽️"
    };
}

arguments.file_text:
@page "/recipes/{Category}"

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

<h1>@Category Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="list-group mt-3">
        @foreach (var recipe in Recipes)
        {
            <a href="/recipe/@recipe.Id" class="list-group-item list-group-item-action">
                <div class="d-flex w-100 justify-content-between">
                    <h5 class="mb-1">@recipe.Title</h5>
                    <small>@RenderStars(recipe.AverageRating) (@recipe.RatingCount ratings)</small>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetRecipesByCategory(Category);
    }

    private static string RenderStars(double rating)
    {
        var full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>Instructions</h3>
            @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </div>

    <div class="mt-4 p-3 border rounded">
        <h4>Rate this Recipe</h4>
        <p class="text-muted">Average: @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>
        <StarRating RecipeId="Recipe.Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= SelectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star stars">
            @(star <= SelectedRating ? "★" : "☆")
        </span>
    }
    @if (Submitted)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating { get; set; }
    private bool Submitted { get; set; }

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        Submitted = true;
    }
}

.star-rating .star {
    font-size: 2rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star-rating .star:hover,
.star-rating .star.selected {
    color: #ffc107;
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Submission.Title" />
            <ValidationMessage For="() => Submission.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Submission.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Submission.Ingredients" />
            <ValidationMessage For="() => Submission.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="Submission.Steps" />
            <ValidationMessage For="() => Submission.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.RecipeSubmission Submission { get; set; } = new();
    private IReadOnlyList<string> Categories { get; set; } = [];
    private bool SubmitSuccess { get; set; }

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(Submission);
        SubmitSuccess = true;
    }
}

