@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>🍳 RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mt-2">
    @foreach (var category in Categories)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                    <p class="card-text">Explore our @category recipes</p>
                    <a href="/recipes/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Japanese" => "🍜",
        "Mediterranean" => "🥗",
        _ => "🍽️"
    };
}

toolArgs.file_text:
@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>Instructions</h3>
            @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </div>

    <div class="mt-4 p-3 border rounded">
        <h4>Rate this Recipe</h4>
        <p class="text-muted">Average: @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>
        <StarRating RecipeId="Recipe.Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= SelectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star stars">
            @(star <= SelectedRating ? "★" : "☆")
        </span>
    }
    @if (Submitted)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int SelectedRating { get; set; }
    private bool Submitted { get; set; }

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        Submitted = true;
    }
}

